def password_entropy_estimate(password: str) -> float:
    pool = 0
    pool += 26 if re.search(r"[a-z]", password) else 0
    pool += 26 if re.search(r"[A-Z]", password) else 0
    pool += 10 if re.search(r"\d", password) else 0
    pool += 33 if re.search(r"[^A-Za-z0-9\s]", password) else 0
    pool += 20 if re.search(r"\s", password) else 0
    pool += 80 if re.search(r"[^\x00-\x7F]", password) else 0
    return len(password) * math.log2(max(pool, 1))


def breached_password(password: str) -> bool:
    if password.casefold() in COMMON_PASSWORDS:
        return True
    if not HIBP_ONLINE_CHECK:
        return False

    digest = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = digest[:5], digest[5:]
    try:
        r = requests.get(
            f"https://api.pwnedpasswords.com/range/{prefix}",
            headers={"Add-Padding": "true", "User-Agent": "registration-validator"},
            timeout=2.5,
        )
        if r.status_code != 200:
            return False
        for line in r.text.splitlines():
            candidate = line.split(":", 1)[0]
            if hmac.compare_digest(candidate, suffix):
                return True
    except requests.RequestException:
        return False
    return False


def too_similar(password: str, candidate: str) -> bool:
    if not candidate or len(candidate) < 3:
        return False
    p, c = policy_key(password), policy_key(candidate)
    if hmac.compare_digest(p, c):
        return True
    if c in p or p in c:
        return True
    return SequenceMatcher(None, p, c).ratio() >= 0.72


def validate_password_field(
    value: Any,
    errors: list[dict[str, str]],
    username_key: str | None,
    email_local: str | None,
    email_domain: str | None,
    display_name: str | None,
) -> str | None:
    if not isinstance(value, str):
        errors.append(error("password", "PASSWORD_TYPE", "Password must be a string."))
        return None

    password = unicodedata.normalize("NFKC", value)
    if len(password) < 12:
        errors.append(error("password", "PASSWORD_TOO_SHORT", "Password must be at least 12 characters."))
    if len(password) > 128 or len(password.encode("utf-8")) > 1024:
        errors.append(error("password", "PASSWORD_TOO_LONG", "Password is too long."))
        return None
    if has_bad_unicode(password):
        errors.append(error("password", "PASSWORD_UNSAFE_CHARACTERS", "Password contains unsafe hidden characters."))
    if password != password.strip():
        errors.append(error("password", "PASSWORD_EDGE_WHITESPACE", "Password cannot start or end with whitespace."))

    classes = sum(bool(re.search(pattern, password)) for pattern in [r"[a-z]", r"[A-Z]", r"\d", r"[^A-Za-z0-9]"])
    if classes < 3:
        errors.append(error("password", "PASSWORD_COMPLEXITY", "Password must use at least 3 character classes."))
    if password_entropy_estimate(password) < 50:
        errors.append(error("password", "PASSWORD_WEAK", "Password is too easy to guess."))
    if re.search(r"(.)\1{3,}", password):
        errors.append(error("password", "PASSWORD_REPEATED", "Password contains too many repeated characters."))

    weak_patterns = ["password", "qwerty", "asdf", "letmein", "welcome", "admin", "123456", "abcdef", "iloveyou"]
    if any(p in policy_key(password) for p in weak_patterns):
        errors.append(error("password", "PASSWORD_COMMON_PATTERN", "Password contains a common pattern."))
    if re.search(r"(19|20)\d{2}", password):
        errors.append(error("password", "PASSWORD_DATE_PATTERN", "Password must not contain obvious years."))

